2446 /// Given a SCEVMulExpr, returns its first operand if its first operand is a
2447 /// constant and the product doesn't overflow in a signed sense. Otherwise,
2448 /// returns std::nullopt. For example, given (10 * X * Y)<nsw>, it returns 10.
2449 /// Notably, if it doesn't have nsw, the multiplication may overflow, and if
2450 /// so, it may not a multiple of 10.
2451 static std::optional<APInt> getConstantCoefficient(const SCEV *Expr) {
2452   if (const auto *Constant = dyn_cast<SCEVConstant>(Expr))
2453     return Constant->getAPInt();
2454   if (const auto *Product = dyn_cast<SCEVMulExpr>(Expr))
2455     if (const auto *Constant = dyn_cast<SCEVConstant>(Product->getOperand(0)))
2456       if (Product->hasNoSignedWrap())
2457         return Constant->getAPInt();
2458   return std::nullopt;
2459 }
